// jsmart custom plugins
var smartyPlugins = function() {
	
	jSmart.prototype.registerPlugin(
		'modifier', 
		'classpaginator', 
		function(txt, pag, pags) {
			if(!txt) return txt;
			pag || (pag = 1);
			pags || (pags = 10);
			
			
			return txt.length > chars ? '<span class="smaller">' + txt + '</span>' : txt;
		}
	);

	jSmart.prototype.registerPlugin(
		'modifier', 
		'fontrepair', 
		function(txt, chars) {
			if(!txt) return txt;
			chars = chars || 50;
			
			return txt.length > chars ? '<span class="smaller">' + txt + '</span>' : txt;
		}
	);

	jSmart.prototype.registerPlugin(
		'modifier', 
		'multilines', 
		function(txt, num, chars) {
			if(!txt) return txt;
			num = num || 3;
			chars = chars || 25;
			var palabras = [];
			for(var i=0;i<num;i++) {
				palabras[i] = _.str.prune(txt,chars,'');
				txt = txt.substr(palabras[i].length);
			}
			palabras = palabras.map(function(est){return '<span>' + _.str.trim(est) + '</span>'});
			return palabras.join('');
		}
	);

	jSmart.prototype.registerPlugin(
		'modifier', 
		'encodeUrl', 
		function(s) {
			if (!s || $.type(s) != 'string') return s;
			s = encodeURI(s);
			return s;
		}
	);

	jSmart.prototype.registerPlugin(
		'modifier', 
		'stripTruncate', 
		function(s,ch) {
			if (!s || $.type(s) != 'string') return s;
			s = html_entity_decode(s);
			s = _.str.stripTags(s);
			if (s.length <= ch) return s;
			return s.substr(0,ch) + '...';
		}
	);
	
	jSmart.prototype.registerPlugin(
		'modifier', 
		'stripTruncateWords', 
		function(s,ch) {
			if (!s || $.type(s) != 'string') return s;
			s = html_entity_decode(s);
			s = _.str.stripTags(s);
			if (s.length <= ch) return s;
			return _.str.prune(s, ch);
		}
	);

	jSmart.prototype.registerPlugin(
		'modifier', 
		'words', 
		function(s,w,maxlen) {
			w = w || 1;
			if (!s || $.type(s) != 'string') return s;
			s = html_entity_decode(s);
			s = _.str.stripTags(s);
			s = _.str.clean(s);
			s = s.replace(/[_-]\s/g," ");
			maxlen = maxlen || s.length;
			var wrds = _.str.words(s);
			if (wrds.length <= w || w > wrds.length) return s;
			return wrds.slice(0, w).join(' ').substr(0,maxlen);
		}
	);
	
	jSmart.prototype.registerPlugin(
		'modifier', 
		'replace', 
		function(s,buscar,reemplazar) {
			buscar || (buscar = false);
			reemplazar || (reemplazar = '');
			if(!buscar) return s;

			var re = new RegExp(buscar, 'gi');
			return s.replace(re,reemplazar);
		}
	);

	jSmart.prototype.registerPlugin(
		'modifier', 
		'resaltar', 
		function(s,buscar) {
			buscar || (buscar = false);
			if(!buscar) return s;
			var buscarArr = buscar.split(' ');
			var mapa = {};
			for(var i=0;i<buscarArr.length;i++) {
				mapa[buscarArr[i]] = ' <strong class="yellow">'+buscarArr[i]+'</strong> ';
			}

			return _replaceAll(s,mapa);

			function _replaceAll(str,mapObj){
			    var re = new RegExp(Object.keys(mapObj).join("|"),"gi");

			    return str.replace(re, function(matched){
			        return mapObj[matched.toLowerCase()];
			    });
			}
			
			return s.replace(re,reemplazar);
		}
	);

	jSmart.prototype.registerPlugin(
		'modifier', 
		'formatoHora', 
		function(s) {
			if (!s || $.type(s) != 'string') return s;
			_stringFecha = s || false;
			if (!_stringFecha) return s;
			var stringFecha = _stringFecha.split(" ");
			if(stringFecha.length < 2) return false;
				
			return stringFecha[1];
		}
	);
	
	jSmart.prototype.registerPlugin(
		'modifier', 
		'formatoFecha', 
		function(s) {
			if (!s || $.type(s) != 'string') return s;
			_stringFecha = s || false;
			if (!_stringFecha) return s;
			var stringFecha = _stringFecha.split(" ")[0];
			var arrayFecha = stringFecha.split("-");
			var numberToMonth = [];
			numberToMonth['01'] = "Ene"; 
			numberToMonth['02'] = "Feb"; 
			numberToMonth['03'] = "Mar"; 
			numberToMonth['04'] = "Abr"; 
			numberToMonth['05'] = "May"; 
			numberToMonth['06'] = "Jun"; 
			numberToMonth['07'] = "Jul"; 
			numberToMonth['08'] = "Ago"; 
			numberToMonth['09'] = "Sep"; 
			numberToMonth['10'] = "Oct"; 
			numberToMonth['11'] = "Nov"; 
			numberToMonth['12'] = "Dic"; 
				
			return arrayFecha[2] + " " + numberToMonth[arrayFecha[1]] + " " + arrayFecha[0];
		}
	);

	jSmart.prototype.registerPlugin(
		'function', 
		'hoy', 
		function(params, s) {
			var meses = new Array ("Enero","Febrero","Marzo","Abril","Mayo","Junio","Julio","Agosto","Septiembre","Octubre","Noviembre","Diciembre");
			var d = new Date();
			return d.getDate() + " de " + meses[d.getMonth()] + " de " + d.getFullYear();
		}
	);

	jSmart.prototype.registerPlugin(
		'function', 
		'mask', 
		function(param) {
			var params = param.param;
			if(!_.has(params,'x') || !_.has(params,'y') || !_.has(params,'w') || !_.has(params,'h') || !_.has(params,'ho')) return "";
			var posX = ((+params.x + (+params.w/2)) / 1200) * 100,
				// posY = ((+params.y +  (+params.h/2)) / +params.ho) * 100;
				posY = ((+params.y ) / +params.ho) * 100;
			// var posX = ((+params.x) / 1200) * 100,
			// 	posY = ((+params.y) / +params.ho) * 100;
			return posX.toFixed() + '% ' + posY.toFixed() + '%';
		}
	);

	jSmart.prototype.registerPlugin(
		'modifier', 
		'formatoMiles', 
		function(s) {
			return _.str.numberFormat(+s,0);
		}
	);

	jSmart.prototype.registerPlugin(
		'modifier', 
		'trim', 
		function(s) {
			if (!s || $.type(s) != 'string') return s;
			return _.str.trim(s);
		}
	);
};


